<template>
    <view
      class="uv-text"
      :class="[]"
      v-if="show"
      :style="{
        margin: margin,
				justifyContent: align === 'left' ? 'flex-start' : align === 'center' ? 'center' : 'flex-end'
      }"
      @tap="clickHandler"
    >
      <text
        :class="['uv-text__price', type && `uv-text__value--${type}`]"
        v-if="mode === 'price'"
        :style="[valueStyle]"
        >№┐Ц</text
      >
      <view class="uv-text__prefix-icon" v-if="prefixIcon">
        <uv-icon
          :name="prefixIcon"
          :customStyle="$uv.addStyle(iconStyle)"
        ></uv-icon>
      </view>
      <uv-link
        v-if="mode === 'link'"
        :text="value"
        :href="href"
        underLine
      ></uv-link>
      <template v-else-if="openType && isMp">
        <button
          class="uv-reset-button uv-text__value"
          :style="[valueStyle]"
          :openType="openType"
          @getuserinfo="onGetUserInfo"
          @contact="onContact"
          @getphonenumber="onGetPhoneNumber"
          @error="onError"
          @launchapp="onLaunchApp"
          @opensetting="onOpenSetting"
          :lang="lang"
          :session-from="sessionFrom"
          :send-message-title="sendMessageTitle"
          :send-message-path="sendMessagePath"
          :send-message-img="sendMessageImg"
          :show-message-card="showMessageCard"
          :app-parameter="appParameter"
        >
          {{ value }}
        </button>
      </template>
      <text
        v-else
        class="uv-text__value"
        :style="[valueStyle]"
        :class="[
          type && `uv-text__value--${type}`,
          lines && `uv-line-${lines}`
        ]"
        >{{ value }}</text
      >
      <view class="uv-text__suffix-icon" v-if="suffixIcon">
        <uv-icon
          :name="suffixIcon"
          :customStyle="$uv.addStyle(iconStyle)"
        ></uv-icon>
      </view>
    </view>
</template>
<script lang="uts">
	import value from './value.js'
	import mpMixin from '@/uni_modules/uv-ui-tools/libs/mixin/mpMixin.js'
	import mixin from '@/uni_modules/uv-ui-tools/libs/mixin/mixin.js'
	import button from '@/uni_modules/uv-ui-tools/libs/mixin/button.js'
	import openType from '@/uni_modules/uv-ui-tools/libs/mixin/openType.js'
	import props from './props.js'
	/**
	 * Text ТќЄТюг
	 * @description ТГцу╗ёС╗ХжЏєТѕљС║єТќЄТюгу▒╗тюежА╣уЏ«СИГуџётИИућетіЪУЃй№╝їтїЁТІгуіХТђЂ№╝їТІеТЅЊућхУ»Ю№╝їТа╝т╝ЈтїќТЌЦТюЪ№╝ї*ТЏ┐ТЇб№╝їУХЁжЊЙТјЦ...уГЅтіЪУЃйсђѓ ТѓетцДтЈ»СИЇт┐ЁтюеСй┐ућеуЅ╣Т«іТќЄТюгТЌХУЄфти▒т«џС╣Ѕ№╝їtextу╗ёС╗ХтЄаС╣јТХхуЏќТѓеУЃйСй┐ућеуџётцДжЃетѕєтю║ТЎ»сђѓ
	 * @tutorial https://www.uvui.cn/components/loading.html
	 * @property {String} 					type		СИ╗жбўжбюУЅ▓
	 * @property {Boolean} 					show		Тў»тљдТўЙуц║№╝ѕж╗ўУ«ц true №╝Ѕ
	 * @property {String | Number}			text		ТўЙуц║уџётђ╝
	 * @property {String}					prefixIcon	тЅЇуй«тЏЙТаЄ
	 * @property {String} 					suffixIcon	тљјуй«тЏЙТаЄ
	 * @property {String} 					mode		ТќЄТюгтцёуљєуџётї╣жЁЇТеАт╝Ј text-ТЎ«жђџТќЄТюг№╝їprice-С╗иТа╝№╝їphone-ТЅІТю║тЈи№╝їname-тДЊтљЇ№╝їdate-ТЌЦТюЪ№╝їlink-УХЁжЊЙТјЦ
	 * @property {String} 					href		mode=linkСИІ№╝їжЁЇуй«уџёжЊЙТјЦ
	 * @property {String | Function} 		format		Та╝т╝ЈтїќУДётѕЎ
	 * @property {Boolean} 					call		mode=phoneТЌХ№╝їуѓ╣тЄ╗ТќЄТюгТў»тљдТІеТЅЊућхУ»Ю№╝ѕж╗ўУ«ц false №╝Ѕ
	 * @property {String} 					openType	т░ЈуеІт║ЈуџёТЅЊт╝ђТќ╣т╝Ј
	 * @property {Boolean} 					bold		Тў»тљду▓ЌСйЊ№╝їж╗ўУ«цnormal№╝ѕж╗ўУ«ц false №╝Ѕ
	 * @property {Boolean} 					block		Тў»тљдтЮЌуіХ№╝ѕж╗ўУ«ц false №╝Ѕ
	 * @property {String | Number} 			lines		ТќЄТюгТўЙуц║уџёУАїТЋ░№╝їтдѓТъюУ«Йуй«№╝їУХЁтЄ║ТГцУАїТЋ░№╝їт░єС╝џТўЙуц║уюЂуЋЦтЈи
	 * @property {String} 					color		ТќЄТюгжбюУЅ▓№╝ѕж╗ўУ«ц '#303133' №╝Ѕ
	 * @property {String | Number} 			size		тГЌСйЊтцДт░Ј№╝ѕж╗ўУ«ц 15 №╝Ѕ
	 * @property {Object | String} 			iconStyle	тЏЙТаЄуџёТаит╝Ј №╝ѕж╗ўУ«ц {fontSize: '15px'} №╝Ѕ
	 * @property {String} 					decoration	ТќЄтГЌУБЁжЦ░№╝їСИІтѕњу║┐№╝їСИГтѕњу║┐уГЅ№╝їтЈ»жђЅтђ╝ none|underline|line-through№╝ѕж╗ўУ«ц 'none' №╝Ѕ
	 * @property {Object | String | Number}	margin		тцќУЙ╣УиЮ№╝їт»╣У▒АсђЂтГЌугдСИ▓№╝їТЋ░тђ╝тйбт╝ЈтЮЄтЈ»№╝ѕж╗ўУ«ц 0 №╝Ѕ
	 * @property {String | Number} 			lineHeight	ТќЄТюгУАїжФў
	 * @property {String} 					align		ТќЄТюгт»╣жйљТќ╣т╝Ј№╝їтЈ»жђЅтђ╝left|center|right№╝ѕж╗ўУ«ц 'left' №╝Ѕ
	 * @property {String} 					wordWrap	ТќЄтГЌТЇбУАї№╝їтЈ»жђЅтђ╝break-word|normal|anywhere№╝ѕж╗ўУ«ц 'normal' №╝Ѕ
	 * @event {Function} click  уѓ╣тЄ╗УДдтЈЉС║ІС╗Х
	 * @example <uv-text text="ТѕЉућетЇЂт╣┤жЮњТўЦ,Ух┤СйаТюђтљјС╣Іу║д"></uv-text>
	 */
	export default {
		name: 'uv-text',
		emits: ['click'],

		mixins: [mpMixin, mixin, value, button, openType, props],




		computed: {
			valueStyle() {
				const style = {
					textDecoration: this.decoration,
					fontWeight: this.bold ? 'bold' : 'normal',
					wordWrap: this.wordWrap,
					fontSize: this.$uv.addUnit(this.size)
				};
				!this.type && (style.color = this.color);
				this.isNvue && this.lines && (style.lines = this.lines);
				if(this.isNvue && this.mode != 'price' && !this.prefixIcon && !this.suffixIcon) {
					 style.flex = 1;
					 style.textAlign = this.align === 'left' ? 'flex-start' : this.align === 'center' ? 'center' : 'right';
				}
				this.lineHeight && (style.lineHeight = this.$uv.addUnit(this.lineHeight));
				!this.isNvue && this.block && (style.display = 'block');
				return this.$uv.deepMerge(style, this.$uv.addStyle(this.customStyle));
			},
			isNvue() {
				let nvue = false



				return nvue
			},
			isMp() {
				let mp = false

				mp = true

				return mp
			}
		},
		data() {
			return {}
		},
		methods: {
			clickHandler() {
				// тдѓТъюСИ║ТЅІТю║тЈиТеАт╝Ј№╝їТІеТЅЊућхУ»Ю
				if (this.call && this.mode === 'phone') {
					uni.makePhoneCall({
						phoneNumber: this.text
					})
				}
				this.$emit('click')
			}
		}
	}
</script>
<style lang="scss" scoped>
	$show-lines: 1;
	$show-reset-button: 1;
	@import '@/uni_modules/uv-ui-tools/libs/css/variable.scss';
	@import '@/uni_modules/uv-ui-tools/libs/css/components.scss';
	@import '@/uni_modules/uv-ui-tools/libs/css/color.scss';
	.uv-text {
		@include flex(row);
		align-items: center;
		flex-wrap: nowrap;
		flex: 1;

		width: 100%;

		&__price {
			font-size: 14px;
			color: $uv-content-color;
		}
		&__value {
			font-size: 14px;
			@include flex;
			color: $uv-content-color;
			flex-wrap: wrap;
			// flex: 1;
			text-overflow: ellipsis;
			align-items: center;
			&--primary {
				color: $uv-primary;
			}
			&--warning {
				color: $uv-warning;
			}
			&--success {
				color: $uv-success;
			}
			&--info {
				color: $uv-info;
			}
			&--error {
				color: $uv-error;
			}
			&--main {
				color: $uv-main-color;
			}
			&--content {
				color: $uv-content-color;
			}
			&--tips {
				color: $uv-tips-color;
			}
			&--light {
				color: $uv-light-color;
			}
		}
	}
</style>